import { useState, useEffect, useCallback, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import './Dashboard.css';

const AREA_OPTIONS = ['RPT', 'CPT'];
const STATUS_OPTIONS = ['Open', 'Closed'];

export default function Dashboard() {
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const context = location.state;

  const [tab, setTab] = useState('create');
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState({ text: '', type: '' });
  const [search, setSearch] = useState('');

  useEffect(() => { if (!context) navigate('/select'); }, [context, navigate]);

  const showMsg = (text, type = 'success') => {
    setMsg({ text, type });
    setTimeout(() => setMsg({ text: '', type: '' }), 3000);
  };

  const fetchRows = useCallback(async () => {
    if (!context) return;
    setLoading(true);
    try {
      const res = await axios.get('/api/observations', {
        params: { company: context.company, financialYear: context.financialYear, business: context.business }
      });
      setRows(res.data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [context]);

  useEffect(() => { fetchRows(); }, [fetchRows]);

  const addRow = async () => {
    setSaving(true);
    try {
      const payload = {
        company: context.company, financialYear: context.financialYear, business: context.business,
        area: '', observation: '', managerComment: '', personResponsibilityAsPerAC: '',
        personResponsible: '', remarks: '', attachment: '', status: 'Open', closingPeriod: '',
      };
      const res = await axios.post('/api/observations', payload);
      setRows(r => [...r, res.data]);
      showMsg('Row added!');
    } catch (e) {
      showMsg('Error adding row', 'error');
    } finally {
      setSaving(false);
    }
  };

  const updateCell = (index, field, value) => {
    setRows(r => r.map((row, i) => i === index ? { ...row, [field]: value } : row));
  };

  const handleBlur = async (index) => {
    const row = rows[index];
    if (!row._id) return;
    try {
      const res = await axios.put(`/api/observations/${row._id}`, {
        company: context.company, financialYear: context.financialYear, business: context.business,
        area: row.area, observation: row.observation, managerComment: row.managerComment,
        personResponsibilityAsPerAC: row.personResponsibilityAsPerAC, personResponsible: row.personResponsible,
        remarks: row.remarks, attachment: row.attachment,
        status: row.status, closingPeriod: row.closingPeriod,
      });
      setRows(r => r.map((ro, i) => i === index ? res.data : ro));
    } catch (e) {
      console.error('Auto-save failed', e);
    }
  };

  const handleAreaChange = async (index, value) => {
    updateCell(index, 'area', value);
    const row = { ...rows[index], area: value };
    if (!row._id) return;
    try {
      const res = await axios.put(`/api/observations/${row._id}`, {
        company: context.company, financialYear: context.financialYear, business: context.business,
        area: value, observation: row.observation, managerComment: row.managerComment,
        personResponsibilityAsPerAC: row.personResponsibilityAsPerAC, personResponsible: row.personResponsible,
        remarks: row.remarks, attachment: row.attachment,
        status: row.status, closingPeriod: row.closingPeriod,
      });
      setRows(r => r.map((ro, i) => i === index ? res.data : ro));
    } catch (e) { console.error(e); }
  };

  const handleStatusChange = async (index, value) => {
    updateCell(index, 'status', value);
    const row = { ...rows[index], status: value };
    if (!row._id) return;
    try {
      await axios.put(`/api/observations/${row._id}`, { ...row, status: value });
    } catch (e) { console.error(e); }
  };

  const handleAttachment = async (index, file) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (e) => {
      const dataUrl = e.target.result;
      updateCell(index, 'attachment', dataUrl);
      updateCell(index, 'attachmentName', file.name);
      const row = rows[index];
      if (!row._id) return;
      try {
        await axios.put(`/api/observations/${row._id}`, {
          ...row, attachment: dataUrl, attachmentName: file.name
        });
      } catch (err) { console.error(err); }
    };
    reader.readAsDataURL(file);
  };

  const deleteRow = async (index) => {
    const row = rows[index];
    if (!window.confirm('Delete this row?')) return;
    try {
      if (row._id) await axios.delete(`/api/observations/${row._id}`);
      setRows(r => r.filter((_, i) => i !== index));
      showMsg('Row deleted');
    } catch (e) { showMsg('Error deleting', 'error'); }
  };

  if (!context) return null;

  // Filter rows based on search
  const filtered = rows.filter(row => {
    if (!search) return true;
    const s = search.toLowerCase();
    return (
      row.area?.toLowerCase().includes(s) ||
      row.personResponsible?.toLowerCase().includes(s) ||
      row.personResponsibilityAsPerAC?.toLowerCase().includes(s) ||
      row.observation?.toLowerCase().includes(s) ||
      row.uniqueKey?.toLowerCase().includes(s) ||
      row.status?.toLowerCase().includes(s) ||
      row.closingPeriod?.toLowerCase().includes(s)
    );
  });

  const closedCount = rows.filter(r => r.status === 'Closed').length;
  const openCount = rows.filter(r => r.status === 'Open').length;

  return (
    <div className="db-bg">
      {/* Header */}
      <div className="db-header">
        <div className="db-header-left">
          <div className="db-logo">AuditPro</div>
          <div className="db-context">
            <span className="ctx-chip">{context.company}</span>
            <span className="ctx-chip">{context.financialYear}</span>
            <span className="ctx-chip">{context.business}</span>
          </div>
        </div>
        <div className="db-header-right">
          <span className="db-welcome">👋 {user?.name}</span>
          <span className="db-role-tag">{user?.role}</span>
          <button onClick={() => navigate('/select')} className="db-back-btn">← Change</button>
          <button onClick={logout} className="db-logout">Logout</button>
        </div>
      </div>

      {/* Tabs */}
      <div className="db-tabs">
        <button className={`db-tab ${tab === 'create' ? 'active' : ''}`} onClick={() => setTab('create')}>📝 Create</button>
        <button className={`db-tab ${tab === 'report' ? 'active' : ''}`} onClick={() => setTab('report')}>📊 Report</button>
      </div>

      {msg.text && <div className={`db-msg ${msg.type}`}>{msg.type === 'error' ? '⚠' : '✓'} {msg.text}</div>}

      {/* CREATE TAB */}
      {tab === 'create' && (
        <div className="db-content">
          <div className="db-toolbar">
            <h2>Audit Observations <span className="db-count">{rows.length} rows</span></h2>
            <div className="toolbar-right">
              <input
                className="search-bar"
                placeholder="🔍 Search by area, person, date, status..."
                value={search}
                onChange={e => setSearch(e.target.value)}
              />
              <button className="db-add-btn" onClick={addRow} disabled={saving}>
                {saving ? '...' : '+ Add Row'}
              </button>
            </div>
          </div>

          {loading ? <div className="db-loading">Loading...</div> : (
            <div className="db-table-wrap">
              <table className="db-table">
                <thead>
                  <tr>
                    <th>S.No.</th>
                    <th>Key</th>
                    <th>Fin. Year</th>
                    <th>Business</th>
                    <th>Area</th>
                    <th>Observation</th>
                    <th>Manager Comment</th>
                    <th>Person Resp. as per AC</th>
                    <th>Person Responsible</th>
                    <th>Remarks & Attachment</th>
                    <th>Closing Period</th>
                    <th>Status</th>
                    <th>Created On</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.length === 0 ? (
                    <tr><td colSpan={14} className="db-empty">{search ? 'No results found.' : 'No rows yet. Click "+ Add Row" to start.'}</td></tr>
                  ) : filtered.map((row, i) => (
                    <tr key={row._id}>
                      <td className="td-center">{i + 1}</td>
                      <td className="td-key">{row.uniqueKey || <span className="td-muted">—</span>}</td>
                      <td className="td-auto">{context.financialYear}</td>
                      <td className="td-auto">{context.business}</td>
                      <td>
                        <select className="cell-select" value={row.area}
                          onChange={e => handleAreaChange(rows.indexOf(row), e.target.value)}>
                          <option value="">Select...</option>
                          {AREA_OPTIONS.map(a => <option key={a}>{a}</option>)}
                        </select>
                      </td>
                      <td>
                        <textarea className="cell-textarea" value={row.observation}
                          onChange={e => updateCell(rows.indexOf(row), 'observation', e.target.value)}
                          onBlur={() => handleBlur(rows.indexOf(row))} placeholder="Observation..." />
                      </td>
                      <td>
                        <textarea className="cell-textarea" value={row.managerComment}
                          onChange={e => updateCell(rows.indexOf(row), 'managerComment', e.target.value)}
                          onBlur={() => handleBlur(rows.indexOf(row))} placeholder="Comment..." />
                      </td>
                      <td>
                        <input className="cell-input" value={row.personResponsibilityAsPerAC}
                          onChange={e => updateCell(rows.indexOf(row), 'personResponsibilityAsPerAC', e.target.value)}
                          onBlur={() => handleBlur(rows.indexOf(row))} placeholder="Name..." />
                      </td>
                      <td>
                        <input className="cell-input" value={row.personResponsible}
                          onChange={e => updateCell(rows.indexOf(row), 'personResponsible', e.target.value)}
                          onBlur={() => handleBlur(rows.indexOf(row))} placeholder="Name..." />
                      </td>
                      <td className="td-remarks">
                        <textarea className="cell-textarea" value={row.remarks}
                          onChange={e => updateCell(rows.indexOf(row), 'remarks', e.target.value)}
                          onBlur={() => handleBlur(rows.indexOf(row))} placeholder="Remarks..." />
                        <label className="attach-btn">
                          📎 {row.attachmentName || 'Attach'}
                          <input type="file" style={{display:'none'}}
                            onChange={e => handleAttachment(rows.indexOf(row), e.target.files[0])} />
                        </label>
                        {row.attachment && (
                          <a className="attach-link" href={row.attachment} download={row.attachmentName || 'file'}>⬇ Download</a>
                        )}
                      </td>
                      <td>
                        <input className="cell-input" type="date" value={row.closingPeriod}
                          onChange={e => updateCell(rows.indexOf(row), 'closingPeriod', e.target.value)}
                          onBlur={() => handleBlur(rows.indexOf(row))} />
                      </td>
                      <td>
                        <span
                          className={`status-pill ${row.status === 'Closed' ? 'closed' : 'open'}`}
                          onClick={() => handleStatusChange(rows.indexOf(row), row.status === 'Open' ? 'Closed' : 'Open')}
                          title="Click to toggle"
                        >
                          {row.status}
                        </span>
                      </td>
                      <td className="td-date">
                        {new Date(row.createdAt).toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' })}
                      </td>
                      <td className="td-actions">
                        <button className="del-btn" onClick={() => deleteRow(rows.indexOf(row))}>🗑</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {/* REPORT TAB */}
      {tab === 'report' && (
        <div className="db-content">
          <div className="db-toolbar">
            <h2>Audit Report</h2>
            <input
              className="search-bar"
              placeholder="🔍 Search..."
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
          </div>
          <div className="report-cards">
            <div className="r-card total"><div className="r-card-num">{rows.length}</div><div className="r-card-label">Total</div></div>
            <div className="r-card open"><div className="r-card-num">{openCount}</div><div className="r-card-label">Open</div></div>
            <div className="r-card closed"><div className="r-card-num">{closedCount}</div><div className="r-card-label">Closed</div></div>
          </div>
          <div className="db-table-wrap">
            <table className="db-table">
              <thead>
                <tr>
                  <th>S.No.</th><th>Key</th><th>Fin. Year</th><th>Business</th><th>Area</th>
                  <th>Observation</th><th>Manager Comment</th><th>Person Resp. as per AC</th>
                  <th>Person Responsible</th><th>Remarks</th><th>Closing Period</th><th>Status</th><th>Created On</th>
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr><td colSpan={13} className="db-empty">No data.</td></tr>
                ) : filtered.map((row, i) => (
                  <tr key={row._id}>
                    <td className="td-center">{i + 1}</td>
                    <td className="td-key">{row.uniqueKey}</td>
                    <td>{context.financialYear}</td>
                    <td>{context.business}</td>
                    <td>{row.area}</td>
                    <td>{row.observation}</td>
                    <td>{row.managerComment}</td>
                    <td>{row.personResponsibilityAsPerAC}</td>
                    <td>{row.personResponsible}</td>
                    <td>{row.remarks}</td>
                    <td>{row.closingPeriod}</td>
                    <td><span className={`status-pill ${row.status === 'Closed' ? 'closed' : 'open'}`}>{row.status}</span></td>
                    <td className="td-date">{new Date(row.createdAt).toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' })}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
